<?php
$pageTitle = 'Incidents & Alerts';
$pageDescription = 'Stonefellow incident response center for alerts, severity workflow, notification routing, and incident event history.';
$pageClass = 'membership-page admin-catalog-page';
require __DIR__ . '/../includes/admin_catalog.php';
require_once __DIR__ . '/../includes/monitoring_alerts.php';
sf_sec_require('admin.ops.manage');
if (($_SERVER['REQUEST_METHOD'] ?? 'GET') === 'POST') {
  $action=(string)($_POST['action']??'');
  if($action==='create_incident'){ $id=sf_mon_create_incident((string)($_POST['title']??''),(string)($_POST['summary']??''),(string)($_POST['severity']??'medium'),'manual'); sf_admin_flash($id?'success':'error',$id?'Incident opened and alerts routed.':'Incident was not created.'); sf_admin_redirect($id?sf_url('admin/incidents.php?incident_id='.$id):null); }
  if($action==='update_incident'){ sf_mon_update_incident((int)($_POST['incident_id']??0),(string)($_POST['status']??'investigating'),(string)($_POST['severity']??''),(string)($_POST['resolution_notes']??'')); sf_admin_flash('success','Incident updated.'); }
  if($action==='event'){ sf_mon_incident_event((int)($_POST['incident_id']??0),(string)($_POST['event_type']??'manual_update'),(string)($_POST['event_status']??'info'),(string)($_POST['message']??'')); sf_admin_flash('success','Incident event added.'); }
  if($action==='route_alert'){ $r=sf_mon_route_alert((int)($_POST['incident_id']??0)); sf_admin_flash('success','Alerts routed: '.(int)$r['created'].' created, '.(int)$r['sent'].' sent.'); }
  if($action==='mark_alert'){ sf_mon_mark_alert((int)($_POST['alert_id']??0),(string)($_POST['status']??'read')); sf_admin_flash('success','Alert updated.'); }
  sf_admin_redirect(sf_url('admin/incidents.php'.(!empty($_POST['incident_id'])?'?incident_id='.(int)$_POST['incident_id']:'')));
}
require __DIR__ . '/../includes/header.php';
$summary=sf_mon_summary();
$incidents=sf_mon_incidents(150);
$alerts=sf_mon_alerts(150);
$rules=sf_mon_rules();
$selectedId=(int)($_GET['incident_id']??($incidents[0]['id']??0));
$selected=$selectedId?sf_mon_incident($selectedId):null;
$events=$selectedId?sf_mon_incident_events($selectedId):[];
sf_admin_shell_start('Incidents & Alerts', 'Incident response v1', 'Track incident severity, status workflow, admin alerts, alert rules, event history, and operational response after failed checks.', 'incidents');
