  <aside class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow"><?= $selected?'Selected':'Create' ?></span><h2><?= $selected?sf_admin_h($selected['title']):'Manual incident' ?></h2></div></div><?php if($selected): ?><div class="sf-admin-detail-list"><div><span>Key</span><strong><?= sf_admin_h($selected['incident_key']) ?></strong></div><div><span>Status</span><strong><?= sf_admin_h($selected['status']) ?></strong></div><div><span>Severity</span><strong><?= sf_admin_h($selected['severity']) ?></strong></div><div><span>Detected</span><strong><?= sf_admin_h($selected['detected_at']) ?></strong></div></div><form class="sf-admin-form" method="post"><?= sf_csrf_field() ?><input type="hidden" name="action" value="update_incident"><input type="hidden" name="incident_id" value="<?= (int)$selected['id'] ?>"><div class="sf-admin-form-grid"><label>Status<?= sf_admin_select('status',['open'=>'Open','investigating'=>'Investigating','monitoring'=>'Monitoring','resolved'=>'Resolved','closed'=>'Closed'],$selected['status']) ?></label><label>Severity<?= sf_admin_select('severity',['low'=>'Low','medium'=>'Medium','high'=>'High','critical'=>'Critical'],$selected['severity']) ?></label></div><label>Resolution Notes<textarea name="resolution_notes" rows="4"<?= sf_admin_form_disabled_attr() ?>><?= sf_admin_h($selected['resolution_notes']??'') ?></textarea></label><div class="sf-admin-form-actions"><button type="submit"<?= sf_admin_form_disabled_attr() ?>>Update Incident</button></div></form><form class="sf-admin-form" method="post"><?= sf_csrf_field() ?><input type="hidden" name="action" value="route_alert"><input type="hidden" name="incident_id" value="<?= (int)$selected['id'] ?>"><div class="sf-admin-form-actions"><button type="submit"<?= sf_admin_form_disabled_attr() ?>>Route Admin Alert</button></div></form><?php endif; ?><form class="sf-admin-form" method="post"><?= sf_csrf_field() ?><input type="hidden" name="action" value="create_incident"><label>Title<input name="title" required<?= sf_admin_form_disabled_attr() ?>></label><label>Severity<?= sf_admin_select('severity',['low'=>'Low','medium'=>'Medium','high'=>'High','critical'=>'Critical'],'medium') ?></label><label>Summary<textarea name="summary" rows="4"<?= sf_admin_form_disabled_attr() ?>></textarea></label><div class="sf-admin-form-actions"><button type="submit"<?= sf_admin_form_disabled_attr() ?>>Create Incident</button></div></form></aside>
</section>
<?php if($selected): ?><section class="sf-admin-two-col sf-admin-two-col-wide"><article class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Incident Timeline</span><h2><?= count($events) ?> events</h2></div></div><div class="sf-admin-list"><?php foreach($events as $ev): ?><article class="sf-admin-list-row"><strong><?= sf_admin_h($ev['event_type']) ?></strong><span><?= sf_admin_h($ev['event_status']) ?> · <?= sf_admin_h($ev['created_at']) ?> · <?= sf_admin_h($ev['display_name'] ?: $ev['email'] ?: 'System') ?></span><p><?= nl2br(sf_admin_h($ev['message'])) ?></p></article><?php endforeach; ?><?php if(!$events): ?><article class="sf-admin-list-row"><strong>No events yet.</strong><p>Incident events will appear here.</p></article><?php endif; ?></div></article><aside class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Add Timeline Event</span><h2>Response note</h2></div></div><form class="sf-admin-form" method="post"><?= sf_csrf_field() ?><input type="hidden" name="action" value="event"><input type="hidden" name="incident_id" value="<?= (int)$selected['id'] ?>"><div class="sf-admin-form-grid"><label>Type<input name="event_type" value="manual_update"<?= sf_admin_form_disabled_attr() ?>></label><label>Status<?= sf_admin_select('event_status',['info'=>'Info','success'=>'Success','warning'=>'Warning','error'=>'Error'],'info') ?></label></div><label>Message<textarea name="message" rows="5" required<?= sf_admin_form_disabled_attr() ?>></textarea></label><div class="sf-admin-form-actions"><button type="submit"<?= sf_admin_form_disabled_attr() ?>>Add Event</button></div></form></aside></section><?php endif; ?>
